<?php require_once __DIR__.'/../config/database.php'; require_once __DIR__.'/../includes/functions.php'; require_login(); $vars=$pdo->query('SELECT * FROM variables ORDER BY id')->fetchAll(); require_once __DIR__.'/../includes/header.php'; ?><div class="container"><h2>Konsultasi Potensi Banjir</h2><form class="card p-4" method="post" action="proses.php"><div class="mb-3"><label>Lokasi</label><input name="location" class="form-control" required></div><div class="row g-3"><?php foreach($vars as $v): $st=$pdo->prepare('SELECT * FROM symptoms WHERE variable_id=? ORDER BY id'); $st->execute([$v['id']]); ?><div class="col-md-6"><label><?=e($v['name'])?></label><select class="form-select" name="symptom[<?=$v['id']?>]" required><?php foreach($st->fetchAll() as $s): ?><option value="<?=$s['id']?>"><?=$s['code']?> - <?=$s['name']?></option><?php endforeach; ?></select></div><?php endforeach; ?></div><textarea class="form-control mt-3" name="notes" placeholder="Catatan"></textarea><button class="btn btn-primary mt-3"><i class="bi bi-cpu"></i> Proses Forward Chaining</button></form></div><?php require_once __DIR__.'/../includes/footer.php'; ?>
